-- 서해선 시간표 시드 (시흥시청·초지)
-- ────────────────────────────────────────────────────────────
-- 원인: TAGO API가 서해선 destination(endSubwayStationNm)을 빈 값으로 반환
--       → subway.py:218-219에서 무조건 '대곡'으로 fallback → 일산행 누락
-- 데이터 소스: tabriz.kr (한국철도 비공식 편성정보 사이트)
--   API: GET https://tabriz.kr/api/timetable_api2.php?line=서해선&stn={역명}
--   서버가 '오늘 다이아'만 반환 → 토요일에 호출하여 토요일 다이아 확보
-- 운영 합의: 평일·일요일 다이아도 토요일과 약간만 다름 + train_no prefix 룰(K71xx=일산, K72xx=대곡)이
--          모든 요일에 일관되므로, 일단 3개 day_type 모두 토요일 다이아로 시드한다.
--          정확한 평일/일요일 다이아는 추후 해당 요일에 fetch_seohae 스크립트로 갱신 가능.
--
-- 적용일: 2026-05-16 (토요일)
-- ────────────────────────────────────────────────────────────

BEGIN;

-- 1. train_no 컬럼 추가 (실시간 API 매칭, prefix 룰 활용용)
ALTER TABLE subway_timetable_entries
    ADD COLUMN IF NOT EXISTS train_no VARCHAR(20);

CREATE INDEX IF NOT EXISTS idx_subway_tt_train_no
    ON subway_timetable_entries (train_no);

-- 2. 기존 서해선 4개 direction 데이터 전부 삭제 (TAGO 기반 잘못된 대곡 라벨링)
DELETE FROM subway_timetable_entries
 WHERE direction IN ('siheung_up', 'siheung_dn', 'choji_up', 'choji_dn');

-- 3. tabriz 토요일 다이아 INSERT — saturday/sunday/weekday 3개 day_type 동일 데이터
--    (라벨링은 정확, 평일·일요일 시각은 토요일과 약간 다를 수 있음)

-- ── saturday ──

-- ── sunday ──

-- ── weekday ──

COMMIT;

-- 총 INSERT: 888건 (74편 × 4 direction... 정정: 296편 × 3 day_type = 888건)